import{F as d,B as o,D as n,S as t,bB as l,O as e,N as s,T as r,V as c}from"./index.7a40d1d8.js";const v={name:"TncPage"},p={class:"tnc-container"},u={class:"tnc-content"},h={class:""};function m(i,a,y,g,f,b){return o(),n("div",p,[a[3]||(a[3]=t("h1",{class:"tnc-title"},"Terms, Conditions & Privacy Policy",-1)),t("div",u,[a[2]||(a[2]=l('<section data-v-1354d0a2><h2 data-v-1354d0a2>1. Introduction</h2><p data-v-1354d0a2>Welcome to SOS Bharat (the &quot;App&quot;), a product of Xavoc Technocrats Pvt. Ltd. (&quot;Company,&quot; &quot;we,&quot; &quot;our,&quot; or &quot;us&quot;). SOS Bharat (sosbharat.com) is a brand owned and operated by Xavoc Technocrats Pvt. Ltd. (xavoc.com). By accessing and using the application, you agree to be bound by these Terms and Conditions and Privacy Policy.</p></section><section data-v-1354d0a2><h2 data-v-1354d0a2>2. Information We Collect</h2><h3 data-v-1354d0a2>2.1 Personal Information</h3><ul data-v-1354d0a2><li data-v-1354d0a2>Name</li><li data-v-1354d0a2>Phone number (for OTP verification)</li><li data-v-1354d0a2>Email address (for secondary verification)</li><li data-v-1354d0a2>Emergency contacts (with their explicit consent)</li><li data-v-1354d0a2>Device ID</li><li data-v-1354d0a2>Location data (only when specifically activated)</li></ul><h3 data-v-1354d0a2>2.2 Location Data Collection</h3><p data-v-1354d0a2>We collect location data only in the following scenarios:</p><ul data-v-1354d0a2><li data-v-1354d0a2>When you press the SOS button</li><li data-v-1354d0a2>When you choose to register as a volunteer at a specific location</li><li data-v-1354d0a2>For discovering nearby volunteers and events</li><li data-v-1354d0a2>For providing location-based services and recommendations</li><li data-v-1354d0a2>For improving our service coverage and response times</li></ul><h3 data-v-1354d0a2>2.3 Usage Information</h3><ul data-v-1354d0a2><li data-v-1354d0a2>News reading preferences</li><li data-v-1354d0a2>Content interaction patterns</li><li data-v-1354d0a2>SOS event data (retained for 90 days)</li><li data-v-1354d0a2>Volunteer ratings and feedback</li><li data-v-1354d0a2>Event participation and interaction data</li><li data-v-1354d0a2>Service usage patterns and preferences</li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>3. How We Use Your Information</h2><h3 data-v-1354d0a2>3.1 Core Functionality</h3><ul data-v-1354d0a2><li data-v-1354d0a2>User authentication and verification</li><li data-v-1354d0a2>Emergency response coordination</li><li data-v-1354d0a2>Volunteer notification system</li><li data-v-1354d0a2>News content personalization</li><li data-v-1354d0a2>Local event discovery and recommendations</li><li data-v-1354d0a2>Service improvement and optimization</li><li data-v-1354d0a2>Research and development of new features</li><li data-v-1354d0a2>Analytics and performance monitoring</li></ul><h3 data-v-1354d0a2>3.2 Emergency Contact System</h3><ul data-v-1354d0a2><li data-v-1354d0a2>Emergency contacts must explicitly accept their role</li><li data-v-1354d0a2>During emergencies, we share: <ul data-v-1354d0a2><li data-v-1354d0a2>With emergency contacts: User&#39;s name and location</li><li data-v-1354d0a2>With volunteers: Only approximate distance</li><li data-v-1354d0a2>Audio broadcasts: Available only to accepted volunteers</li></ul></li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>4. Data Storage and Security</h2><p data-v-1354d0a2>All data is stored in Indian data centers with industry-standard security measures and encryption both in transit and at rest.</p></section><section data-v-1354d0a2><h2 data-v-1354d0a2>5. Your Rights and Data Deletion</h2><p data-v-1354d0a2>You have the right to request data deletion through profile settings. The deletion process includes:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Immediate removal from active systems</li><li data-v-1354d0a2>Permanent deletion within 90 days</li><li data-v-1354d0a2>Deletion of all media content</li><li data-v-1354d0a2>Email confirmation upon completion</li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>6. Volunteer System</h2><p data-v-1354d0a2>The volunteer system operates under the following conditions:</p><ul data-v-1354d0a2><li data-v-1354d0a2>No formal verification process currently implemented</li><li data-v-1354d0a2>Location sharing limited to emergency events</li><li data-v-1354d0a2>Rating system may affect volunteer status</li><li data-v-1354d0a2>We reserve the right to suspend volunteer status based on feedback</li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>7. Legal Compliance</h2><p data-v-1354d0a2>This policy complies with:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Information Technology Act, 2000</li><li data-v-1354d0a2>Information Technology Rules, 2011</li><li data-v-1354d0a2>Personal Data Protection Bill guidelines</li><li data-v-1354d0a2>Other applicable Indian laws and regulations</li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>8. Contact Information</h2><p data-v-1354d0a2>For questions about this privacy policy or to exercise your rights, please contact:</p><p data-v-1354d0a2>Xavoc Technocrats Pvt. Ltd.</p><ul data-v-1354d0a2><li data-v-1354d0a2>Website: <a href="https://www.xavoc.com" target="_blank" rel="noopener noreferrer" data-v-1354d0a2>www.xavoc.com</a></li><li data-v-1354d0a2>Brand Website: <a href="https://sosbharat.com/#/" target="_blank" rel="noopener noreferrer" data-v-1354d0a2>www.sosbharat.com</a></li></ul></section><section data-v-1354d0a2><h2 data-v-1354d0a2>9. Updates to Policy</h2><p data-v-1354d0a2>We may update this policy periodically. Users will be notified of significant changes via in-app notifications, email notifications, and app store updates.</p></section><section data-v-1354d0a2><h2 data-v-1354d0a2>10. End User License Agreement (EULA)</h2><h3 data-v-1354d0a2>10.1 Acceptance of Terms</h3><p data-v-1354d0a2>By downloading, installing, or using the SOS Bharat application (&quot;App&quot;), you agree to be bound by this End User License Agreement (&quot;EULA&quot;). If you do not agree to these terms, do not use the App.</p><h3 data-v-1354d0a2>10.2 Nature of Service</h3><h3 data-v-1354d0a2>10.2.1 Supplementary Service</h3><p data-v-1354d0a2>The App is designed and provided as a supplementary support system during distress situations. It is NOT intended to replace:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Emergency services (Police, Ambulance, Fire)</li><li data-v-1354d0a2>Professional medical care</li><li data-v-1354d0a2>Official emergency response systems</li><li data-v-1354d0a2>Standard emergency procedures</li></ul><h3 data-v-1354d0a2>10.2.2 User Acknowledgment</h3><p data-v-1354d0a2>By using this App, you acknowledge and agree that:</p><ul data-v-1354d0a2><li data-v-1354d0a2>This is a secondary support system</li><li data-v-1354d0a2>You will follow all standard emergency procedures first</li><li data-v-1354d0a2>You will not rely solely on this App during emergencies</li><li data-v-1354d0a2>Response times and availability of volunteers cannot be guaranteed</li></ul><h3 data-v-1354d0a2>10.3 Data Usage and Permissions</h3><h3 data-v-1354d0a2>10.3.1 Broad Data Usage Rights</h3><p data-v-1354d0a2>By accepting this EULA, you grant us permission to:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Collect, store, and process your personal information</li><li data-v-1354d0a2>Use your data for service improvement and optimization</li><li data-v-1354d0a2>Analyze usage patterns for feature development</li><li data-v-1354d0a2>Share anonymized data with partners and third parties</li><li data-v-1354d0a2>Utilize your content for marketing and promotional purposes</li><li data-v-1354d0a2>Process your data for research and development</li><li data-v-1354d0a2>Create derivative works from aggregated user data</li></ul><h3 data-v-1354d0a2>10.4 Disclaimer of Warranties</h3><p data-v-1354d0a2>The App is provided &quot;as is&quot; without any warranties of:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Service availability</li><li data-v-1354d0a2>Response time</li><li data-v-1354d0a2>Accuracy of information</li><li data-v-1354d0a2>Volunteer availability or quality</li><li data-v-1354d0a2>Emergency response effectiveness</li></ul><h3 data-v-1354d0a2>10.5 Limitation of Liability</h3><p data-v-1354d0a2>By using this App, you agree that we shall not be liable for:</p><ul data-v-1354d0a2><li data-v-1354d0a2>Any delays in emergency response</li><li data-v-1354d0a2>Actions or inactions of volunteers</li><li data-v-1354d0a2>Accuracy of location data</li><li data-v-1354d0a2>Service interruptions</li><li data-v-1354d0a2>Data loss or breach</li><li data-v-1354d0a2>Any consequential damages</li></ul></section>',10)),t("div",h,[e(c,{flat:"",color:"primary",onClick:a[0]||(a[0]=w=>i.$router.back()),class:"back-button"},{default:s(()=>[e(r,{name:"mdi-keyboard-backspace",style:{"font-size":"18px","margin-top":"-1px"}}),a[1]||(a[1]=t("span",{class:"q-pl-xs",style:{"font-size":"10px","font-weight":"800"}}," Back ",-1))]),_:1})])])])}var S=d(v,[["render",m],["__scopeId","data-v-1354d0a2"]]);export{S as default};
